proof fn phi_1_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_2_suffix_zero_equals_self(ex: Execution<int>)
    ensures
        ex.suffix(0) == ex,
{
    execution_equality::<int>(ex.suffix(0), ex);
}

proof fn phi_3_suffix_composition_equals_addition(ex: Execution<int>, i: nat, j: nat)
    ensures
        ex.suffix(i).suffix(j) == ex.suffix(i + j),
{
    execution_equality::<int>(ex.suffix(i).suffix(j), ex.suffix(i + j));
}

proof fn phi_4_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_5_always_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}
